package main

import (
	"flag"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"text/template"
	"time"
)

// Built-in fallback template, used when no --template file is provided.
// It exposes the same data/funcs as an external template:
//   {{ .Issuer }}   {{ .Upstream }}   {{ indent N .PEM }}
const kongTemplate = `_format_version: "3.0"
_transform: true

# Generated by "zk gen-config". Edit kong/kong.tmpl.yml, not this file.
# issuer: {{ .Issuer }}

services:
  - name: sample-api
    url: {{ .Upstream }}
    routes:
      - name: api-route
        paths:
          - /api
        strip_path: false
    plugins:
      - name: jwt
        config:
          # Find the credential by the token's ` + "`iss`" + ` claim.
          key_claim_name: iss
          claims_to_verify:
            - exp
          run_on_preflight: true

consumers:
  - username: zitadel
    jwt_secrets:
      - key: "{{ .Issuer }}"
        algorithm: RS256
        rsa_public_key: |
{{ indent 10 .PEM }}
`

func runGenConfig(args []string) error {
	fs := flag.NewFlagSet("gen-config", flag.ExitOnError)
	issuer := fs.String("issuer", env("ZITADEL_ISSUER", "http://localhost:8080"),
		"issuer string Kong matches against the token's iss claim")
	internalURL := fs.String("internal-url", env("ZITADEL_INTERNAL_URL", "http://host.docker.internal:8080"),
		"URL this tool uses to reach Zitadel for JWKS")
	hostHeader := fs.String("host-header", env("ZITADEL_HOST_HEADER", "localhost"),
		"Host header to send (Zitadel's Traefik routes on it)")
	apiUpstream := fs.String("api-upstream", env("API_UPSTREAM", "http://api:8000"),
		"upstream URL exposed to the template as {{ .Upstream }}")
	templatePath := fs.String("template", env("KONG_TEMPLATE", ""),
		"path to an editable kong template; falls back to the built-in if empty/missing")
	out := fs.String("out", env("OUT_PATH", "/kong-config/kong.yml"), "output path for kong.yml")
	retries := fs.Int("retries", 30, "JWKS fetch attempts before giving up")
	interval := fs.Duration("interval", 2*time.Second, "delay between JWKS fetch attempts")
	fs.Parse(args)

	issuerClean := strings.TrimRight(*issuer, "/")
	internalClean := strings.TrimRight(*internalURL, "/")

	tmplText, source, err := loadTemplate(*templatePath)
	if err != nil {
		return err
	}
	logf("using %s template", source)

	pemStr, kid, err := fetchWithRetry(internalClean, *hostHeader, *retries, *interval)
	if err != nil {
		return err
	}
	logf("using signing key kid=%s", kid)

	body, err := render(tmplText, issuerClean, *apiUpstream, pemStr)
	if err != nil {
		return err
	}
	if dir := filepath.Dir(*out); dir != "" {
		if err := os.MkdirAll(dir, 0o755); err != nil {
			return err
		}
	}
	if err := os.WriteFile(*out, []byte(body), 0o644); err != nil {
		return err
	}
	logf("wrote %s (issuer=%s, upstream=%s)", *out, issuerClean, *apiUpstream)
	return nil
}

func fetchWithRetry(internalURL, host string, attempts int, interval time.Duration) (string, string, error) {
	var lastErr error
	for i := 1; i <= attempts; i++ {
		pemStr, kid, err := fetchSigningPEM(internalURL, host)
		if err == nil {
			return pemStr, kid, nil
		}
		lastErr = err
		logf("attempt %d/%d: Zitadel not ready (%v)", i, attempts, err)
		time.Sleep(interval)
	}
	return "", "", fmt.Errorf("giving up after %d attempts: %w", attempts, lastErr)
}

// loadTemplate returns the template text and a human label for logging. An
// empty or missing path falls back to the built-in template.
func loadTemplate(path string) (text, source string, err error) {
	if path == "" {
		return kongTemplate, "built-in", nil
	}
	b, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			logf("template %s not found; using built-in", path)
			return kongTemplate, "built-in", nil
		}
		return "", "", err
	}
	return string(b), path, nil
}

var templateFuncs = template.FuncMap{
	// indent prefixes every line with n spaces — for placing a PEM under a
	// YAML block scalar (rsa_public_key: |).
	"indent": func(n int, s string) string {
		pad := strings.Repeat(" ", n)
		lines := strings.Split(s, "\n")
		for i, line := range lines {
			lines[i] = pad + line
		}
		return strings.Join(lines, "\n")
	},
}

func render(tmplText, issuer, upstream, pemStr string) (string, error) {
	tmpl, err := template.New("kong").Funcs(templateFuncs).Parse(tmplText)
	if err != nil {
		return "", fmt.Errorf("parsing template: %w", err)
	}
	var sb strings.Builder
	data := struct{ Issuer, Upstream, PEM string }{issuer, upstream, pemStr}
	if err := tmpl.Execute(&sb, data); err != nil {
		return "", fmt.Errorf("rendering template: %w", err)
	}
	return sb.String(), nil
}

func logf(format string, a ...any) {
	fmt.Fprintf(os.Stderr, "[zk gen-config] "+format+"\n", a...)
}
